    This function takes a graph in the form of a dictionary of dictionaries and returns the shortest path between the start and end nodes. 
    If there is no path between the start and end nodes, it returns None.
    """
    distances = {node: float('infinity') for node in graph}
    distances[start] = 0

    for _ in range(len(graph) - 1):
        for node in graph:
            for neighbor, weight in graph[node].items():
                if distances[node] + weight < distances[neighbor]:
                    distances[neighbor] = distances[node] + weight

    return distances[end] if distances[end] != float('infinity') else None

